        if (n <= MAX_VAL) {
            return is_prime_sieve[n];
        }
        // Fallback for values potentially exceeding MAX_VAL, though constraints suggest this shouldn't be needed
        if (n <= 1) return false;
        for (int i = 2; i * i <= n; ++i) {
            if (n % i == 0) return false;
